def mystery(x):
    if not isinstance(x, int) or x < 10:
        return False

    s = str(x)
    digits = [int(d) for d in s]

    # Product of digits must equal count of divisors
    product = 1
    for d in digits:
        product *= d

    if product == 0:
        return False

    # Count divisors
    count = 0
    for i in range(1, int(x**0.5) + 1):
        if x % i == 0:
            count += 1
            if i != x // i:
                count += 1

    return product == count

